<template>
  <div class="flex-space-between">
    <div class="g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">遥控器</span>
        <div class="buttons">
          <div class="g-button update-button" @click="handleRefresh">更新</div>
          <div class="g-button control-button" @click="toggleRightItem">
            控制界面
          </div>
        </div>
      </div>
      <div class="container-content">
        <div class="g-section-layout">
          <div class="section">
            <div
              class="g-kv-pair"
              v-for="(label, key) in displayLabels"
              :key="key"
            >
              <div class="label">{{ label }}</div>
              <div class="value">{{ getDisplayValue(remoteData, key) }}</div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 动作控制区域 -->
    <div class="g-page-container-with-header" v-if="showRightItem">
      <div class="container-content">
        <div class="button-group">
          <div
            class="button-section"
            v-for="(actions, type) in groupedActions"
            :key="type"
          >
            <div class="section-title">{{ type }}</div>
            <div class="buttons">
              <button
                v-for="action in actions"
                :key="action.id"
                @click="handleAction(action)"
              >
                {{ action.desc }}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws'
import { useCommand } from '@/hooks/useCommand'
import { useDataMerge } from '@/hooks/useDataMerge'
import { ElMessage } from 'element-plus'
import proto from '@/utils/sdkapi_pb.js'

const store = useWslStore()
const { received } = storeToRefs(store)
const { sendGetStatusData, sendActionCommand } = useCommand(store)

const displayLabels = {
  devid: '设备ID',
  devname: '设备名称',
  devtype: '设备类型',
  devdesp: '设备描述',
  status: '状态',
  timestamp: '时间'
}

const getDisplayValue = (item, key) => {
  const value = item[key]
  if (key === 'timestamp') {
    const date = new Date(value)
    return date.toLocaleString()
  }
  return value ?? '-'
}

const remoteList = useDataMerge(
  computed(() => received.value?.statusData?.remoteControlDataList || [])
).mergedData

const remoteData = computed(() => {
  return remoteList.value.length > 0
    ? remoteList.value[0]
    : { devdesp: '暂无', timestamp: Date.now() }
})

const showRightItem = ref(true)

const handleRefresh = () => {
  sendGetStatusData('remote')
}

const toggleRightItem = () => {
  showRightItem.value = !showRightItem.value
}

// 按 type 分组
const actionList = useDataMerge(
  computed(() => received.value?.statusData?.actionDataList || []),
  { idField: 'id' } // id是唯一标识
).mergedData

const groupedActions = computed(() => {
  const result = {}
  actionList.value.forEach((action) => {
    const type = action.type || '其他'
    if (!result[type]) {
      result[type] = []
    }
    result[type].push(action)
  })
  return result
})

// 点击动作按钮
const handleAction = (action) => {
  sendActionCommand(action.id)
}

watch(
  () => received.value,
  (resp) => {
    if (!resp || resp.command !== proto.Command.CMD_RUN_ACTION) return

    const errorCode = resp.errorCode
    const errorMessage = resp.errorMessage
    const actionStatus = resp.actionResponse?.actionStatus

    if (errorCode === proto.ErrorCode.ERROR_CODE_SUCCESS) {
      if (actionStatus === proto.ActionStatus.ACT_FINISHED) {
        ElMessage.success('动作执行完成')
      } else {
        ElMessage.info('动作正在执行中')
      }
    } else {
      ElMessage.error(errorMessage || '动作执行失败')
    }
  },
  { deep: true }
)
</script>

